type RawConcept = {
  id: string;
  topicId: string;
  subtopicId: string;
  levelId: string;
  partId: string;
  relation: string;
  subject: string;
  object: string;
  answerKind?: string;
  difficulty?: number;
  distractorGroup?: string;
  tags?: string[];
  context?: string;
  introducedIn?: "A" | "B" | "C";
};

type RawConceptSet = {
  id: string;
  concepts: RawConcept[];
};

function toConceptSet(raw: RawConceptSet): { id: string; concepts: Concept[] } {
  const concepts: Concept[] = (raw.concepts ?? []).map((c) => ({
    id: String(c.id),
    topicId: String(c.topicId),
    subtopicId: String(c.subtopicId),
    levelId: String(c.levelId),
    partId: String(c.partId),
    relation: String(c.relation),
    subject: String(c.subject),
    object: String(c.object),
    answerKind: c.answerKind === "long" ? "long" : "short",
    difficulty: Number(c.difficulty ?? 1) as any,
    distractorGroup: c.distractorGroup ? String(c.distractorGroup) : undefined,
    tags: Array.isArray(c.tags) ? c.tags.map(String) : undefined,
    context: c.context ? String(c.context) : undefined,
    introducedIn: c.introducedIn === "B" || c.introducedIn === "C" ? c.introducedIn : "A",
  }));

  return { id: String(raw.id), concepts };
}

